join (values
  -- ── AI Agents (5) ────────────────────────────────────────
  ('ai-agents','agentgpt','AgentGPT','Run autonomous AI agents in your browser.','Deploy goal-driven AI agents that browse the web, write code, and execute multi-step plans—all from your browser with no setup required.','https://agentgpt.reworkd.ai',null,true,'5 agent runs/day','Free · Pro $40/mo',true,'{"ai-agent","autonomous","gpt"}','AgentGPT — Free Autonomous AI Agent in Browser','Run self-directed AI agents free in your browser. No code needed.'),
